// A sample sales order, the kind a webhook or ERP export would deliver.
return [{ json: {
  orderId: 'SO-1001',
  currency: 'EUR',
  buyerLeitwegId: 'LEITWEG-01',
  supplier: { name: 'Seller GmbH', vatId: 'DE123456789', street: 'Hauptstrasse 1', city: 'Berlin', postalCode: '10115', country: 'DE' },
  customer: { name: 'Buyer GmbH', vatId: 'DE987654321', street: 'Marktplatz 2', city: 'Munich', postalCode: '80331', country: 'DE' },
  lines: [
    { description: 'Consulting services', qty: 10, unit: 'HUR', price: 100, vat: 19 },
    { description: 'License fee', qty: 1, unit: 'C62', price: 500, vat: 19 },
  ],
} }];

// Map the order onto the beliq EN 16931 invoice shape and compute totals.
const o = $json;
const lines = o.lines.map((l) => ({
  description: l.description,
  quantity: l.qty,
  unitCode: l.unit,
  unitPrice: l.price,
  lineTotal: Math.round(l.qty * l.price * 100) / 100,
  vatRate: l.vat,
  vatCategoryCode: 'S',
}));
const totalNet = Math.round(lines.reduce((s, l) => s + l.lineTotal, 0) * 100) / 100;
const vatRate = lines[0] ? lines[0].vatRate : 0;
const totalTax = Math.round(totalNet * vatRate) / 100;
const totalGross = Math.round((totalNet + totalTax) * 100) / 100;
const invoice = {
  number: o.orderId.replace('SO-', 'INV-'),
  issueDate: '2026-01-15',
  dueDate: '2026-02-14',
  currencyCode: o.currency,
  buyerReference: o.buyerLeitwegId,
  seller: { name: o.supplier.name, vatId: o.supplier.vatId, address: { street: o.supplier.street, city: o.supplier.city, postalCode: o.supplier.postalCode, countryCode: o.supplier.country } },
  buyer: { name: o.customer.name, vatId: o.customer.vatId, address: { street: o.customer.street, city: o.customer.city, postalCode: o.customer.postalCode, countryCode: o.customer.country } },
  lines,
  taxSummary: [{ vatCategoryCode: 'S', vatRate, taxableAmount: totalNet, taxAmount: totalTax }],
  paymentMeans: { typeCode: '58', iban: 'DE89370400440532013000' },
  totalNetAmount: totalNet,
  totalTaxAmount: totalTax,
  totalGrossAmount: totalGross,
};
return [{ json: { invoice } }];
